import{_ as e,o as a,c as t,j as p,a as b,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"露营物品套组","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/露营物品套组.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/露营物品套组.md"}'),n={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/露营物品套组.md"};function o(d,r,_,l,i,c){return a(),t("div",null,[...r[0]||(r[0]=[p("h1",{id:"露营物品套组",tabindex:"-1"},[b("露营物品套组 "),p("a",{class:"header-anchor",href:"#露营物品套组","aria-label":'Permalink to "露营物品套组"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"灵魂蓝调015")])])],-1),s('<h1 id="露营物品套组-1" tabindex="-1">露营物品套组 <a class="header-anchor" href="#露营物品套组-1" aria-label="Permalink to &quot;露营物品套组&quot;">​</a></h1><p>露营物品套组<br> 250</p><p>顾名思义，这是一个用来在影片春游之余，提高生活质量的露营物品杂物堆。大概能满足使用者们对露营这一活动绝大部分不切实际的幻想，因此堆放着一堆用到或者用不到的神奇小物件。当然，使用者无需担心这堆东西放哪的问题，所有东西都可以用空间胶囊来解释。使用时，可以选择只取出其中的一样或展开全部东西。</p><p>总之轮回者们戎马半生，享受享受也是很正常的吧。</p><p>露营套组内包含以下物品：</p><p>露营帐篷（默认为少女风格，可自选其他配色）：<br> 柔软且耐用的帐篷，整体为粉色或薄荷绿色搭配可爱的花纹，材质柔韧耐用且防水，前提是雨不会很大。帐篷内部空间宽敞，配有舒适的软垫和LED灯串照明，整体风格温暖舒适。整体大小为双人帐篷款式，不过提前预留了相当大的娱乐空间，所以挤一挤睡四五个人也完全不成问题。</p><p>便携式烤肉架与炭火套装：<br> 金属材质，折叠设计，易于携带，还包括一个优质炭火套组及点火装置，是野外烤肉的不二之选。主神空间选配版额外配有温控功能和防风罩，时刻确保火焰稳定，确保在任何环境下都能享受完美的烤肉体验。</p><p>烤棉花糖用的木棍：<br> 烤棉花糖专用长木棍，耐高温、光滑无刺，特别适合烤棉花糖。随本物品额外附赠一整袋露营烧烤专用棉花糖，每次影片结束自动补满。棍子上还有专门的刻度线，就算猴子也可以轻松掌握好棉花糖的受热程度。</p><p>迷你火锅炉：<br> 精致的小火锅炉具，提供烤肉之外的另一选择，适合在凉爽的夜晚和朋友们一起煮火锅。可选4格火锅格模式，并随炉提供不同风味的汤底包。附带一个小小的全息功能，能将你的清汤锅底伪装成红汤或其他锅底，或许，可以把面前这个锅底传给别人？。</p><p>露营料理工具包：<br> 套装包含锋利的小刀套组、木制砧板、多用途厨具（汤勺、叉子、夹子等），一切都精致且易于携带。当然，禁止使用厨具进行追逐打闹。</p><p>露营用餐具套装：<br> 带有可爱图案的餐具套装，包括碗、盘、筷子和勺子等，可包含有多套。材料轻便耐用，方便清洗。但其实直接收回的话，也可以直接自动完成清洗。</p><p>咖啡煮制套装：<br> 包含一个迷你咖啡壶、手摇磨豆机和小巧的煤气炉。适合在迎接清晨的朝阳中煮一壶香浓的咖啡，同时也有相应带过滤杯的茶壶套组。另外，如果上述两种饮料都不喜欢，或许也可以拿来手磨豆浆。</p><p>野餐篮：<br> 一个采用天然杉木材质编织，造型简约的野餐篮子，充满田园风格。里面井井有条地装着一堆完全不能当正餐吃的零食或糕点，可以在?幕间自行补充更换里面的东西。提着它去给森林里的外婆送吃的吧，记得小心那里的大灰狼先生。</p><p>野餐垫：<br> 超大尺寸的防水野餐垫，柔软且图案可自定义，适合在草地或沙滩上铺开供大家坐下休息或享用美食。不管怎么说，有这么一张垫子，无论坐在上面吃什么都像是在野餐了。</p><p>露天便携式餐桌椅：<br> 如果不习惯野餐垫，还有轻便的折叠桌椅组合，带软垫和靠背，专为舒适而设计。桌面贴心带有防滑处理，适合放置各种餐具和饮料。同时可自行选配白色塑料大排档椅，助您随时随地，一键发病。</p><p>便携音响：<br> 用于播放轻松的音乐，营造气氛，音响材质防水且抗摔，可蓝牙连接且为充电式，充分确保户外环境下的使用。或许可以用来搭配上述大排档椅子播放意义不明的鼓点。</p><p>露天露营灯具：<br> 小巧的可充电露营灯，可以挂在帐篷顶上或手持使用，亮度可调节，灯光柔和不刺眼，可以根据露营时代，自动更换为煤油提灯款式。同时还有夜晚的星空顶灯光模式，或许可以弥补野外露营时夜晚阴天的遗憾。</p><p>便携式冰箱<br> 虽说是便携，但依然有20L左右的容量，不过好在不用真的考虑其大小。内部已经提前保存好了饮料、肉类等生鲜物品，默认储存有可供5人享受3天的量，每次回归时会自动补满，也可以自行用其他东西补充。冰箱可以是核能供电，支持长时间保冷，内部有多个隔间。虽说食材直接保存在空间胶囊里也不会腐败，但是，谁又会拒绝在炎炎夏日中的一瓶冰镇饮料呢。</p><p>便携制冰机：<br> 更直接的，还有这款小巧但高效的制冰机，尺寸在30-40厘米宽度左右，电源已经被改为核能供电，适合在露营时制作冰块用于冷饮或冰沙。随机器附一套粉色冷饮杯。或许是对于露营来说性价比最低的机器，但你真的需要它时，它能带来最极致的享受。</p><p>便携式户外投影仪：<br> 一台小巧的户外投影仪搭配便携式的投影幕布，投影仪为充电式并自带大容量储存卡，包含了一堆经典影片，可以根据自己的需要自行下载额外视频。或者直接使手机投屏，投影地图或文档以塑造工作氛围。希望你在进入主神空间之前没买过这玩意，不过现在已经不用考虑这个了，享受悠闲的夜晚时光吧。</p><p>户外取暖器：<br> 小型便携式的取暖器，适合在寒冷天气使用，在露营的夜晚为大家提供温暖。无烟无味，使用安全。使用时会给人带来室内暖桌般的享受，所以在野外也会从里面长出猫来吗。</p><p>应急毛毯：<br> 轻便且保暖的毛毯，具有超强的保温性能，适合在夜间或气温较低时使用。毛毯可卷起，便于收纳。可提供大尺寸多人毛毯，供多人卷在一起共同取暖。虽说多人使用的场景似乎有些不太常见，只能问问隔壁粉红书需不需要吧。</p><p>便携式微风风扇：<br> 小巧可挂的充电式户外风扇，适合夏天露营时使用，能带来清凉的微风，配有可调节风速功能。如果实在想要把它换成空调的话......试着对它讲讲冷笑话怎么样？</p><p>露营杂物收纳包：<br> 为了整理各种小物品而设计的收纳包，有多个拉链口袋，方便收纳手机、钥匙、纸巾等杂物。同时能储存的还有露营产生的各类生活垃圾，保护环境，轮回者有责。</p><p>便携式太阳能充电器：<br> 小型、折叠式的太阳能充电板，附带小蓄电池，适合为露营套组内的所有物品和手机充电。轻巧且环保，非常适合没有电源的露营场地。但是.....主神空间产出的东西真的还需要充电吗。</p><p>折叠式观景椅：<br> 特别设计的折叠椅，轻便、舒适，可以在露营时摆放在任何地方。通常配有柔软靠背，适合长时间坐着欣赏日出、日落或夜晚的星空。可以让你好好享受一场日光浴，我的意思是，假使您在影片内能见到正常的太阳的话。</p><p>户外折叠式遮阳伞：<br> 非常有用的遮阳伞，插在地上既能遮挡阳光，也能防止轻微的风雨。可以在伞下悠闲地享受你的露营，不用担心被晒伤或被突然的阵雨打扰。当然，也可以让你假装看不到上一条中不太正常的太阳。</p><p>便携式望远镜：<br> 用于观星或欣赏远处美景的迷你望远镜。二次元中的少女们常常会坐在山顶或草地上，通过望远镜欣赏远方的风景，享受宁静的时光。而你，则可以用它来欣赏山顶或草地上的二次元少女们。</p><p>手持小型风景绘本与绘画颜料包：<br> 适合喜欢绘画或写作的角色。可以在露营时一边享受风景，一边记录下感受或快速绘制风景，增加露营的文艺感。不过，大部分时间这个本会被拿去绘制地图或者记录些别的。</p><p>便携式相机：<br> 轻便的数码或拍立得相机，比起手绘或许少点文艺，但多了几分实用，可以记录下露营过程中的所有美好瞬间，尤其是风景或伙伴们的笑脸，留下难忘的回忆。当然，除了回忆，要是能留下同伴再好不过。</p><p>折叠式吊床：<br> 轻便可携带的吊床，适合挂在两棵树之间。之后可以躺在上面，一边摇晃，一边看着蓝天和漂浮的白云，非常适合放松或小憩。有时候比起帐篷，这个才是更安全的选择。</p><p>钓鱼套装：<br> 钓鱼必备的小型套装，包括一根轻便的伸缩鱼竿，还有各种大小的鱼钩、鱼饵、浮标和备用线。便携式收纳盒让它们井井有条，你可以随时准备好进行垂钓。另外套装内底部藏有50元钱，可以方便你偷偷去菜市场买鱼，或者直接v给st。</p><p>户外露营用桌上游戏：<br> 小型便携的桌上游戏，可以是纸牌，棋盘或者其他桌游。用以在露营时打发时间，增添乐趣。适合与同伴们围坐在一起，享受轻松的娱乐时光。最后，一起开始一段令人愉快的跑团时光吧。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',35)])])}const m=e(n,[["render",o]]);export{f as __pageData,m as default};
